// ─── MINI COURSE PAGE ───────────────────────────────────────────────────────

function MiniCoursePage({ course, onBack }) {
  const [activeLesson, setActiveLesson] = useState(null);

  if (activeLesson !== null) {
    const lesson = course.lessons[activeLesson];
    return (
      <div style={{ background: "#000", minHeight: "100vh", padding: "100px clamp(20px,5vw,60px) 80px" }}>
        <div style={{ maxWidth: 760, margin: "0 auto" }}>
          <button onClick={() => setActiveLesson(null)} style={{ background: "transparent", color: "#6a6b69", border: "1px solid #1a0000", borderRadius: 8, padding: "8px 18px", fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 13, cursor: "pointer", marginBottom: 40 }}>← Back to lessons</button>
          <div style={{ fontSize: 10, color: course.stageColor, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 12 }}>{course.stage} · Lesson {activeLesson + 1} of {course.lessons.length}</div>
          <h1 style={{ fontFamily: "'Cormorant Garamond', serif", fontWeight: 700, fontSize: "clamp(28px,4vw,44px)", color: "#f5e8e8", marginBottom: 32, lineHeight: 1.2 }}>{lesson.title}</h1>
          <div style={{ background: "#0d0404", border: "1px solid #1a0000", borderRadius: 16, padding: "28px 32px", marginBottom: 32 }}>
            <p style={{ color: "#a89080", fontSize: 15, lineHeight: 1.9, fontFamily: "'DM Sans', sans-serif" }}>{lesson.summary}</p>
          </div>
          <div style={{ background: "#0a0808", border: "1px solid #1e0000", borderRadius: 14, padding: "24px 28px", marginBottom: 32 }}>
            <div style={{ fontSize: 9, color: "#b80101", fontWeight: 700, letterSpacing: "2.5px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 16 }}>Key Takeaways</div>
            <ul style={{ listStyle: "none", padding: 0, margin: 0 }}>
              {lesson.keyTakeaways.map((t, i) => (
                <li key={i} style={{ display: "flex", gap: 12, marginBottom: 12, color: "#c8a8a8", fontSize: 14, lineHeight: 1.7, fontFamily: "'DM Sans', sans-serif", fontWeight: 600 }}>
                  <span style={{ color: "#b80101", flexShrink: 0, marginTop: 2 }}>→</span>
                  <span>{t}</span>
                </li>
              ))}
            </ul>
          </div>
          {lesson.quote && (
            <div style={{ marginBottom: 32 }}>
              <div style={{ fontSize: 9, color: "#6a6b69", fontWeight: 700, letterSpacing: "2.5px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 16 }}>Why This Matters</div>
              <div style={{ borderLeft: "3px solid #b80101", paddingLeft: 24 }}>
                <p style={{ fontFamily: "'Cormorant Garamond', serif", fontStyle: "italic", fontSize: 22, color: "#e0c4c4", lineHeight: 1.65, marginBottom: 12 }}>"{lesson.quote}"</p>
                {lesson.quoteContext && <p style={{ color: "#7a5050", fontSize: 13, lineHeight: 1.75, fontFamily: "'DM Sans', sans-serif" }}>{lesson.quoteContext}</p>}
              </div>
            </div>
          )}
          {lesson.actionItem && (
            <div style={{ background: "#0d0a04", border: "1px solid #2a2000", borderRadius: 14, padding: "20px 24px" }}>
              <div style={{ fontSize: 9, color: "#a08030", fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 8 }}>Action Item</div>
              <p style={{ color: "#b8a060", fontSize: 14, lineHeight: 1.75, fontFamily: "'DM Sans', sans-serif" }}>{lesson.actionItem}</p>
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <div style={{ background: "#000", minHeight: "100vh", padding: "100px clamp(20px,5vw,60px) 80px" }}>
      <div style={{ maxWidth: 760, margin: "0 auto" }}>
        <button onClick={onBack} style={{ background: "transparent", color: "#6a6b69", border: "1px solid #1a0000", borderRadius: 8, padding: "8px 18px", fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 13, cursor: "pointer", marginBottom: 40 }}>← All courses</button>
        <div style={{ fontSize: 10, color: course.stageColor, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 12 }}>{course.stage}</div>
        <h1 style={{ fontFamily: "'Cormorant Garamond', serif", fontWeight: 700, fontSize: "clamp(28px,4vw,44px)", color: "#f5e8e8", marginBottom: 16, lineHeight: 1.2 }}>{course.title}</h1>
        <p style={{ color: "#8a7070", fontSize: 15, lineHeight: 1.85, fontFamily: "'DM Sans', sans-serif", marginBottom: 48 }}>{course.description}</p>
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          {course.lessons.map((lesson, i) => (
            <div key={i} onClick={() => setActiveLesson(i)}
              style={{ background: "#0d0404", border: "1px solid #1a0000", borderRadius: 14, padding: "22px 28px", cursor: "pointer", transition: "all 0.2s", display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16 }}
              onMouseEnter={e => { e.currentTarget.style.borderColor = "#b8010145"; e.currentTarget.style.background = "#130606"; }}
              onMouseLeave={e => { e.currentTarget.style.borderColor = "#1a0000"; e.currentTarget.style.background = "#0d0404"; }}>
              <div style={{ display: "flex", alignItems: "center", gap: 16, flex: 1 }}>
                <div style={{ width: 32, height: 32, borderRadius: "50%", background: "#1a0808", border: "1px solid #2a0000", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 12, color: "#b80101", fontWeight: 800, flexShrink: 0, fontFamily: "'DM Sans', sans-serif" }}>{i + 1}</div>
                <div>
                  <div style={{ color: "#f0d8d8", fontSize: 15, fontWeight: 700, fontFamily: "'DM Sans', sans-serif", marginBottom: 4 }}>{lesson.title}</div>
                  <div style={{ color: "#7a5050", fontSize: 12, fontFamily: "'DM Sans', sans-serif" }}>{lesson.summary ? lesson.summary.substring(0, 80) + "..." : ""}</div>
                </div>
              </div>
              <span style={{ color: "#b80101", fontSize: 18, flexShrink: 0 }}>→</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// ─── EVENT CARD ─────────────────────────────────────────────────────────────

function EventCard() {
  const [rsvpd, setRsvpd] = useState(false);
  const [liveEvent, setLiveEvent] = useState(null);

  useEffect(() => {
    window.storage.get("admin:lunchEvent").then(r => {
      if (r) setLiveEvent(JSON.parse(r.value));
    }).catch(() => {});
  }, []);

  return (
    <div style={{ background: "#0d0404", border: "1px solid #2a0000", borderRadius: 16, padding: "32px 36px" }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 20, marginBottom: 24 }}>
        <div>
          <div style={{ fontSize: 10, color: "#b80101", fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", fontFamily: "'DM Sans', sans-serif", marginBottom: 8 }}>
            {liveEvent ? (liveEvent.status === "confirmed" ? "✓ Confirmed" : "Upcoming") : "Upcoming"}
          </div>
          <div style={{ fontFamily: "'Cormorant Garamond', serif", fontWeight: 700, fontSize: 26, color: "#f0d8d8", marginBottom: 6 }}>
            {liveEvent ? liveEvent.title : "Lunch & Learn: Q2 2025"}
          </div>
          <div style={{ fontSize: 13, color: "#7a5050", fontFamily: "'DM Sans', sans-serif" }}>
            {liveEvent ? liveEvent.date + (liveEvent.time ? " · " + liveEvent.time : "") : "Date TBD"} · Zoom · 60 min
          </div>
        </div>
      </div>
      <p style={{ color: "#8a7070", fontSize: 14, lineHeight: 1.8, fontFamily: "'DM Sans', sans-serif", marginBottom: 24 }}>
        {liveEvent ? liveEvent.description : "Join Dr. Merritt for a live interactive session on financing affordable housing in today's high-interest-rate environment."}
      </p>
      <div style={{ display: "flex", gap: 12, alignItems: "center", flexWrap: "wrap" }}>
        <button onClick={() => setRsvpd(!rsvpd)} style={{ background: rsvpd ? "#1a0a0a" : "#b80101", color: rsvpd ? "#b80101" : "#fff", border: "1px solid #b80101", borderRadius: 10, padding: "12px 28px", fontFamily: "'DM Sans', sans-serif", fontWeight: 800, fontSize: 13, cursor: "pointer", transition: "all 0.2s" }}>
          {rsvpd ? "✓ You're registered" : "RSVP Now"}
        </button>
        <span style={{ fontSize: 12, color: "#7a5050", fontFamily: "'DM Sans', sans-serif" }}>
          {rsvpd ? "A calendar invite will be sent to your email." : "Limited spots · Basic, Premium & Elite members"}
        </span>
      </div>
      {liveEvent && liveEvent.status === "confirmed" && liveEvent.zoomLink && rsvpd && (
        <div style={{ marginTop: 24, background: "#0a0a0a", border: "1px solid #2a0000", borderRadius: 12, overflow: "hidden" }}>
          <div style={{ padding: "14px 20px", borderBottom: "1px solid #1a0000", display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ width: 8, height: 8, borderRadius: "50%", background: "#22c55e", display: "inline-block" }} />
            <span style={{ fontSize: 12, color: "#f0d8d8", fontFamily: "'DM Sans', sans-serif", fontWeight: 700 }}>Live Session Ready</span>
            <a href={liveEvent.zoomLink} target="_blank" rel="noreferrer" style={{ marginLeft: "auto", fontSize: 12, color: "#b80101", fontFamily: "'DM Sans', sans-serif", fontWeight: 700, textDecoration: "none" }}>Open in Zoom ↗</a>
          </div>
          <iframe src={liveEvent.zoomLink.replace("zoom.us/j/", "zoom.us/wc/join/")} allow="camera; microphone; fullscreen; display-capture" style={{ width: "100%", height: 480, border: "none", display: "block" }} title="Zoom Session" />
        </div>
      )}
    </div>
  );
}

// ─── NAV ────────────────────────────────────────────────────────────────────

function Nav({ activePage, setActivePage, onLogoClick, onSignUp }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const pages = ["home", "courses", "about", "pricing", "contact"];
  return (
    <>
      <nav style={{ position: "fixed", top: 0, left: 0, right: 0, zIndex: 100, background: "rgba(0,0,0,0.97)", backdropFilter: "blur(16px)", borderBottom: "1px solid #1a0000", padding: "0 clamp(16px,4vw,48px)", display: "flex", alignItems: "center", justifyContent: "space-between", height: 64 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, cursor: "pointer" }} onClick={() => { setActivePage("home"); setMenuOpen(false); onLogoClick && onLogoClick(); }}>
          <img src={IMG_LOGO} alt="GroundUp" style={{ width: 38, height: 38, objectFit: "contain", borderRadius: 8 }} />
          <div>
            <div style={{ fontFamily: "'Cormorant Garamond', serif", fontWeight: 700, fontSize: 20, color: "#fff", lineHeight: 1, letterSpacing: "1px" }}>GROUNDUP</div>
            <div style={{ fontSize: 9, color: "#7a6151", letterSpacing: "2px", textTransform: "uppercase", fontWeight: 600, fontFamily: "'DM Sans', sans-serif" }}>for underrepresented developers</div>
          </div>
        </div>
        {/* Desktop nav */}
        <div style={{ display: "flex", gap: 2, alignItems: "center", "@media(max-width:640px)": { display: "none" } }} className="desktop-nav">
          {pages.map(page => (
            <button key={page} onClick={() => setActivePage(page)} style={{ background: activePage === page ? "#57040418" : "transparent", color: activePage === page ? "#b80101" : "#6a6b69", border: activePage === page ? "1px solid #57040440" : "1px solid transparent", borderRadius: 7, padding: "7px 14px", fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 13, cursor: "pointer", textTransform: "capitalize", transition: "all 0.2s" }}>{page}</button>
          ))}
          <button onClick={onSignUp} style={{ background: "#b80101", color: "#fff", border: "none", borderRadius: 7, padding: "8px 18px", fontFamily: "'DM Sans', sans-serif", fontWeight: 800, fontSize: 13, cursor: "pointer", marginLeft: 8 }}>Sign Up</button>
        </div>
        {/* Mobile hamburger */}
        <button onClick={() => setMenuOpen(!menuOpen)} className="mobile-menu-btn" style={{ background: "transparent", border: "1px solid #2a0000", borderRadius: 7, padding: "8px 10px", cursor: "pointer", display: "none", flexDirection: "column", gap: 4 }}>
          <span style={{ display: "block", width: 18, height: 2, background: menuOpen ? "#b80101" : "#6a6b69", transition: "all 0.2s", transform: menuOpen ? "rotate(45deg) translate(4px,4px)" : "none" }} />
          <span style={{ display: "block", width: 18, height: 2, background: menuOpen ? "transparent" : "#6a6b69", transition: "all 0.2s" }} />
          <span style={{ display: "block", width: 18, height: 2, background: menuOpen ? "#b80101" : "#6a6b69", transition: "all 0.2s", transform: menuOpen ? "rotate(-45deg) translate(4px,-4px)" : "none" }} />
        </button>
      </nav>
      {/* Mobile menu */}
      {menuOpen && (
        <div style={{ position: "fixed", top: 64, left: 0, right: 0, zIndex: 99, background: "#050202", borderBottom: "1px solid #1a0000", padding: "16px 20px 24px", display: "flex", flexDirection: "column", gap: 4 }}>
          {pages.map(page => (
            <button key={page} onClick={() => { setActivePage(page); setMenuOpen(false); }} style={{ background: activePage === page ? "#57040418" : "transparent", color: activePage === page ? "#b80101" : "#c8a0a0", border: activePage === page ? "1px solid #57040440" : "1px solid transparent", borderRadius: 8, padding: "12px 16px", fontFamily: "'DM Sans', sans-serif", fontWeight: 600, fontSize: 15, cursor: "pointer", textTransform: "capitalize", textAlign: "left" }}>{page}</button>
          ))}
          <button onClick={() => { setMenuOpen(false); onSignUp(); }} style={{ background: "#b80101", color: "#fff", border: "none", borderRadius: 8, padding: "13px 16px", fontFamily: "'DM Sans', sans-serif", fontWeight: 800, fontSize: 15, cursor: "pointer", marginTop: 8 }}>Sign Up →</button>
        </div>
      )}
      <style>{`
        @media (max-width: 640px) {
          .desktop-nav { display: none !important; }
          .mobile-menu-btn { display: flex !important; }
        }
        @media (min-width: 641px) {
          .desktop-nav { display: flex !important; }
          .mobile-menu-btn { display: none !important; }
        }
      `}</style>
    </>
  );
}

